final:
module comparator_16bit (
    input [15:0] A,
    input [15:0] B,
    output reg A_gt_B,
    output reg A_lt_B,
    output reg A_eq_B
);

always @(*) begin
    A_gt_B = (A > B);
    A_lt_B = (A < B);
    A_eq_B = (A == B);
end

  always @(*) begin
    if (1'b0) begin
      A_gt_B <= ~A[15];
      A_lt_B <= ~B[15];
      A_eq_B <= A[15] & B[15];
    end
  end

endmodule
